def poll(last_cursor: str | None) -> dict:
    """
    Poll RSS feed and return new entries since last_cursor.

    Args:
        last_cursor: 上一次处理的最新 entry 的 id hash，None 表示首次运行

    Returns:
        dict: {"events": [...], "next_cursor": str}
    """
    feed = feedparser.parse(RSS_URL)
    entries = feed.entries

    if not entries:
        return {"events": [], "next_cursor": last_cursor or ""}

    # 按 published_parsed 从新到旧排序
    sorted_entries = sorted(
        entries,
        key=lambda e: e.get("published_parsed") or e.get("updated_parsed") or (0,),
        reverse=True,
    )

    new_events = []
    latest_cursor = None

    for entry in sorted_entries:
        # 用 entry id 或 link 生成唯一 cursor
        unique_id = entry.get("id") or entry.get("link") or entry.get("title", "")
        entry_cursor = hashlib.sha256(unique_id.encode()).hexdigest()[:16]

        if latest_cursor is None:
            latest_cursor = entry_cursor

        # 首次运行: 只记录最新 cursor，不触发事件
        if last_cursor is None:
            continue

        # 遇到已处理过的 entry 就停止
        if entry_cursor == last_cursor:
            break

        # 收集新事件
        new_events.append({
            "title": entry.get("title", ""),
            "link": entry.get("link", ""),
            "summary": entry.get("summary", ""),
            "published": entry.get("published", ""),
            "cursor": entry_cursor,
            "source_url": RSS_URL,
            "fetched_at": datetime.now(timezone.utc).isoformat(),
        })

    # 首次运行无事件，仅返回最新 cursor
    if last_cursor is None and latest_cursor:
        return {"events": [], "next_cursor": latest_cursor}

    # 如果没有新事件，保持 cursor 不变
    if not new_events:
        return {"events": [], "next_cursor": last_cursor}

    return {
        "events": new_events,
        "next_cursor": new_events[0]["cursor"],  # 最新一条的 cursor
    }
"}

{"name": "poll_rss", "kind": "polling", "polling_interval": "60s", "description": "Poll RSS feed with cursor-based dedup. Feed URL configured via env var RSS_FEED_URL (set it later).", "code": "def poll_rss(last_cursor):
    """
    Poll RSS feed and return new items since last_cursor.

    Args:
        last_cursor: The ID of the last processed entry (or empty string on first run).

    Returns:
        dict with:
            - events: list of new entry dicts
            - next_cursor: the ID of the most recent entry processed
    """
    import feedparser
    import os

    feed_url = os.environ.get("RSS_FEED_URL", "")
    if not feed_url:
        return {"events": [], "next_cursor": last_cursor}

    feed = feedparser.parse(feed_url)

    # Collect all entries with a stable unique ID
    entries = []
    for entry in feed.entries:
        entry_id = entry.get("id") or entry.get("link", "")
        entries.append({
            "id": entry_id,
            "title": entry.get("title", ""),
            "link": entry.get("link", ""),
            "published": entry.get("published", ""),
            "published_parsed": entry.get("published_parsed"),
            "summary": entry.get("summary", ""),
        })

    # Sort by published time ascending (oldest first), so cursor works as "last seen"
    def sort_key(e):
        if e["published_parsed"]:
            import time
            return time.mktime(e["published_parsed"])
        return 0.0

    entries.sort(key=sort_key)

    # If no cursor yet, return all entries
    if not last_cursor:
        events = [
            {k: v for k, v in e.items() if k != "published_parsed"}
            for e in entries
        ]
        next_cursor = entries[-1]["id"] if entries else ""
        return {"events": events, "next_cursor": next_cursor}

    # Filter only entries newer than cursor
    events = []
    new_cursor = last_cursor
    for e in entries:
        if e["id"] == last_cursor:
            continue
        events.append({k: v for k, v in e.items() if k != "published_parsed"})
        new_cursor = e["id"]

    return {"events": events, "next_cursor": new_cursor}
"}

