import xml.etree.ElementTree as ET
from datetime import datetime, timezone
import hashlib

# ========== 配置区 ==========
# 在这里设置你的 RSS 订阅地址（后面随时可以改）
RSS_URL = ""
# ===========================

def poll(last_cursor=None):
    """
    轮询 RSS feed，返回新条目事件。

    Args:
        last_cursor: 上次最后一条的 id（guid），用于增量获取

    Returns:
        {"events": [...], "next_cursor": "..."}
    """
    if not RSS_URL:
        return {
            "events": [],
            "next_cursor": last_cursor or ""
        }

    try:
        resp = requests.get(RSS_URL, timeout=30)
        resp.raise_for_status()
    except Exception as e:
        # 获取失败时不丢 cursor，下次继续
        return {
            "events": [{
                "event": "rss_poll_error",
                "data": {"error": str(e), "url": RSS_URL}
            }],
            "next_cursor": last_cursor or ""
        }

    root = ET.fromstring(resp.content)

    # 兼容 RSS 2.0 和 Atom
    items = []

    # RSS 2.0 格式
    for item in root.iter('item'):
        title = item.findtext('title', '').strip()
        link = item.findtext('link', '').strip()
        description = item.findtext('description', '').strip()
        pub_date = item.findtext('pubDate', '').strip()
        guid = item.findtext('guid', link).strip()  # guid 优先，fallback 到 link

        items.append({
            "id": guid,
            "title": title,
            "link": link,
            "description": description,
            "pub_date": pub_date,
        })

    # Atom 格式
    if not items:
        for entry in root.iter('{http://www.w3.org/2005/Atom}entry'):
            title = entry.findtext('{http://www.w3.org/2005/Atom}title', '').strip()
            link_el = entry.find('{http://www.w3.org/2005/Atom}link')
            link = link_el.get('href', '') if link_el is not None else ''
            summary = entry.findtext('{http://www.w3.org/2005/Atom}summary', '').strip()
            published = entry.findtext('{http://www.w3.org/2005/Atom}published', '').strip()
            id_el = entry.findtext('{http://www.w3.org/2005/Atom}id', link)

            items.append({
                "id": id_el,
                "title": title,
                "link": link,
                "description": summary,
                "pub_date": published,
            })

    if not items:
        return {
            "events": [],
            "next_cursor": last_cursor or ""
        }

    # --- cursor 去重逻辑 ---
    if last_cursor:
        cursor_found = False
        new_events = []

        for item in items:
            if item["id"] == last_cursor:
                cursor_found = True
                continue
            if cursor_found:
                new_events.append({
                    "event": "new_rss_item",
                    "data": {
                        "id": item["id"],
                        "title": item["title"],
                        "link": item["link"],
                        "description": item["description"],
                        "pub_date": item["pub_date"],
                        "source_url": RSS_URL,
                    }
                })

        # 如果 cursor 没找到（比如 feed 重置），返回全部
        if not cursor_found:
            new_events = [{
                "event": "new_rss_item",
                "data": {
                    "id": item["id"],
                    "title": item["title"],
                    "link": item["link"],
                    "description": item["description"],
                    "pub_date": item["pub_date"],
                    "source_url": RSS_URL,
                }
            } for item in items]
    else:
        # 首次轮询，返回所有条目
        new_events = [{
            "event": "new_rss_item",
            "data": {
                "id": item["id"],
                "title": item["title"],
                "link": item["link"],
                "description": item["description"],
                "pub_date": item["pub_date"],
                "source_url": RSS_URL,
            }

{"name": "poll_rss", "kind": "polling", "polling_interval": "60s", "description": "Poll an RSS feed for new entries with cursor-based dedup. Configure RSS_URL inside the function code.", "code": "import feedparser
from datetime import datetime, timezone

def poll_rss(last_cursor: str = "") -> dict:
    """
    Poll RSS feed for new items.

    Args:
        last_cursor: ID of the most recently processed entry (empty string on first run).

    Returns:
        dict with keys:
          - events: list of new entry dicts
          - next_cursor: latest processed entry ID for next poll
    """
    # ⚠️ TODO: Replace with your actual RSS feed URL
    RSS_URL = "https://example.com/rss"

    if not RSS_URL or RSS_URL == "https://example.com/rss":
        return {"events": [], "next_cursor": last_cursor}

    try:
        feed = feedparser.parse(RSS_URL)
        events = []
        latest_id = last_cursor

        for entry in feed.entries:
            # Use entry id, or fallback to link, as the unique cursor
            entry_id = entry.get("id", entry.get("link", ""))
            if not entry_id:
                continue

            # Skip entries already seen (cursor comparison)
            if last_cursor and entry_id <= last_cursor:
                continue

            # Build structured event
            published_struct = entry.get("published_parsed")
            if published_struct:
                published_iso = datetime(*published_struct[:6], tzinfo=timezone.utc).isoformat()
            else:
                published_iso = None

            events.append({
                "title": entry.get("title", ""),
                "link": entry.get("link", ""),
                "summary": entry.get("summary", ""),
                "published": published_iso,
                "id": entry_id,
            })

            # Track the latest entry ID as cursor
            if entry_id > latest_id:
                latest_id = entry_id

        return {
            "events": events,
            "next_cursor": latest_id or last_cursor,
        }

    except Exception as e:
        return {
            "events": [],
            "next_cursor": last_cursor,
            "error": str(e),
        }
"}

{"name": "rss_poller", "kind": "polling", "polling_interval": "60s", "description": "Poll RSS/Atom feed, supports cursor-based dedup. Set RSS_URL env var for feed address.", "code": "import urllib.request
import xml.etree.ElementTree as ET
from datetime import datetime, timezone
import os
import json

def poll(last_cursor):
    """
    Poll RSS/Atom feed.

    Args:
        last_cursor: ISO timestamp string of last poll, or None on first run.

    Returns:
        dict with:
          - events: list of new items [{title, link, published, summary}, ...]
          - next_cursor: ISO timestamp of this poll (to pass next time)
    """
    feed_url = os.environ.get("RSS_URL", "")
    if not feed_url:
        return {"events": [], "next_cursor": last_cursor}

    now_iso = datetime.now(timezone.utc).isoformat()

    try:
        req = urllib.request.Request(
            feed_url,
            headers={"User-Agent": "Forgify-RSS-Poller/1.0"}
        )
        with urllib.request.urlopen(req, timeout=30) as resp:
            data = resp.read()
    except Exception as e:
        print(f"Failed to fetch RSS: {e}")
        return {"events": [], "next_cursor": last_cursor}

    events = []
    try:
        root = ET.fromstring(data)
    except ET.ParseError as e:
        print(f"Failed to parse RSS XML: {e}")
        return {"events": [], "next_cursor": last_cursor}

    # Determine if it's RSS 2.0 or Atom
    tag = root.tag

    if tag == "rss":
        # RSS 2.0 format
        channel = root.find("channel")
        if channel is None:
            return {"events": [], "next_cursor": now_iso}
        items = channel.findall("item")
        for item in items:
            title_el = item.find("title")
            link_el = item.find("link")
            pub_el = item.find("pubDate")
            desc_el = item.find("description")

            title = title_el.text if title_el is not None and title_el.text else "(no title)"
            link = link_el.text if link_el is not None and link_el.text else ""
            pub_date_str = pub_el.text if pub_el is not None and pub_el.text else ""
            summary = desc_el.text if desc_el is not None and desc_el.text else ""

            # Try to parse pubDate to compare with cursor
            cursor_time = None
            if last_cursor:
                try:
                    cursor_time = datetime.fromisoformat(last_cursor)
                except:
                    cursor_time = None

            # Simple dedup: if we have a cursor, try to parse pubDate
            item_time = None
            if pub_date_str:
                try:
                    # RSS pubDate: e.g. "Mon, 01 Jan 2024 12:00:00 GMT"
                    from email.utils import parsedate_to_datetime
                    item_time = parsedate_to_datetime(pub_date_str)
                except:
                    pass

            # If item has a timestamp and cursor exists, skip older items
            if cursor_time and item_time and item_time <= cursor_time:
                continue

            events.append({
                "title": title,
                "link": link,
                "published": pub_date_str,
                "summary": summary
            })

    elif tag == "feed":
        # Atom format
        ns = {"atom": "http://www.w3.org/2005/Atom"}
        entries = root.findall("atom:entry", ns) or root.findall("entry")
        for entry in entries:
            title_el = entry.find("atom:title", ns) or entry.find("title")
            link_el = entry.find("atom:link", ns) or entry.find("link")
            pub_el = entry.find("atom:published", ns) or entry.find("published") or entry.find("atom:updated", ns) or entry.find("updated")
            summary_el = entry.find("atom:summary", ns) or entry.find("summary") or entry.find("atom:content", ns) or entry.find("content")

            title = title_el.text if title_el is not None and title_el.text else "(no title)"
            link = ""
            if link_el is not None:
                link = link_el.attrib.get("href", "")
            pub_date_str = pub_el.text if pub_el is not None and pub_el.text else ""
            summary = summary_el.text if summary_el is not None and summary_el.text else ""

            cursor_time = None
            if last_cursor:
                try:
                    cursor_time = datetime.fromisoformat(last_cursor)
                except:
                    cursor_time = None

            item_time = None
            if pub_date_str:
                try:
                    item_time = datetime.fromisoformat(pub_date_str.replace("Z", "+00:00"))
                except:
                    pass

            if cursor_time and item_time and item_time <= cursor_time:
                continue

            events.append({
                "title": title,
                "link": link,
                "published": pub_date_str,
                "summary": summary
            })

    # Return new events in chronological order (oldest first)
    return {
        "events": events,
        "next_cursor": now_iso
    }
"}
